  "studyMethods": [
    {
      "title": "1. Question-Driven Learning",
      "summary": "For this exam block, the fastest route is not full lecture-note coverage. The fastest route is to let Weekly Exercises and past papers expose the real gaps.",
      "bullets": [
        "concept",
        "method choice",
        "derivation step",
        "calculation",
        "exam wording"
      ]
    },
    {
      "title": "2. Active Recall",
      "summary": "Recognition is not enough. In the exam, the method must be pulled from memory under pressure.",
      "bullets": [
        "Close the notes.",
        "Write the rule, steps, assumptions, or proof skeleton from memory.",
        "Then compare and correct.",
        "definitions",
        "theorem conditions",
        "decision rules",
        "model assumptions",
        "common proof patterns",
        "“when to use which method” triggers"
      ]
    },
    {
      "title": "3. Spaced Revisits",
      "summary": "A question solved once is not learned permanently. Revisit spacing is how you stop it from fading.",
      "bullets": [
        "`D+1`: revisit the next day",
        "`D+3`: revisit three days later",
        "`D+7`: revisit one week later",
        "hard questions",
        "high-value methods",
        "frequent errors",
        "anything that felt familiar but unstable"
      ]
    },
    {
      "title": "4. Interleaving",
      "summary": "If all questions in a set use the same method, you may be training pattern memory, not method selection. Exams require identification before execution.",
      "bullets": [
        "Early stage: work topic-by-topic",
        "Middle stage: mix related topics",
        "Late stage: use fully mixed sets and past papers",
        "statistics methods",
        "finance / forecasting method selection",
        "proof / logic pattern recognition"
      ]
    },
    {
      "title": "5. Worked Examples + Self-Explanation",
      "summary": "When a question is completely blocked, a worked example reduces wasted struggle. But copying is not enough; self-explanation is what turns it into learning.",
      "bullets": [
        "why this step is valid",
        "what rule or condition is being used",
        "what would go wrong if the condition failed"
      ]
    },
    {
      "title": "6. Error Taxonomy",
      "summary": "Wrong answers are only useful if you know why they happened.",
      "bullets": [
        "concept not understood",
        "wrong method selected",
        "condition or assumption forgotten",
        "algebra / arithmetic slip",
        "interpretation error",
        "ran out of time",
        "mistake type",
        "brief cause",
        "prevention rule for next time"
      ]
    },
    {
      "title": "7. Long-Duration Simulation",
      "summary": "These are long UK-style papers. You are not only training correctness; you are training sustained output for 3-4 hours.",
      "bullets": [
        "start with 60-90 minute timed blocks",
        "then move to half papers",
        "then near-full or full papers",
        "simulate the real order, time pressure, and fatigue"
      ]
    }
  ],
